"""
MKT Christ Commentary — Jeremiah chapters 4–6 (fill script)
Run: python3 scripts/zc-christ-jeremiah-4-6-fill.py

Ch 4: "Return" call, circumcision of hearts, uncreation vision — the cosmic scope of sin and the depth
       of divine judgment that the cross absorbs.
Ch 5: The search for one righteous person — only Christ satisfies it; sea-boundary, the word as fire.
Ch 6: Final warnings, the ancient paths with rest, incense/offerings rejected, the assayer's test.

Key Christological classifications:
- 4:4 heart-circumcision → Rom 2:28-29; Col 2:11-12
- 4:10 Jeremiah's protest → Christ as advocate bearing deception's consequence (he bore our confusion)
- 4:19-21 Jeremiah's anguish → Christ's deeper identification with human suffering (Luke 19:41-44)
- 4:23-26 uncreation vision → 2 Cor 5:17; Rev 21:1-5 — Christ as the new-creation answer
- 5:1 search for one righteous → Rom 5:19 — Christ is the one exception found
- 5:22 sea boundary → Mark 4:41 — Christ commands the sea
- 6:16 ancient paths / find rest → Matt 11:28-29 — Christ's invitation to rest
- 6:20 offerings not acceptable → Heb 10:5-10 — Christ's body as the accepted offering
- 6:27-30 the assayer's test → 1 Cor 3:13-15 — Christ the refining fire
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
"4": {
"1": "<p>YHWH&apos;s call &quot;return to me&quot; (not merely &quot;return&quot;) frames repentance as a personal return to the God of the covenant. Christ is both the one who issues this call as YHWH&apos;s incarnate Word (John 1:14) and the one who makes the return possible: he comes down to meet those who cannot find their way back. His parable of the prodigal son (Luke 15:20) is the enacted form of this verse — the father running toward the returning son is YHWH of Jeremiah 4:1.</p>",
"2": "<p>&quot;In truth, justice, and righteousness&quot; — the three covenant virtues that Israel&apos;s oaths lack. Christ embodies all three: he is the truth (John 14:6), he brings justice to the nations (Matt 12:18-21, citing Isa 42), and he is made righteousness for us (1 Cor 1:30). The oath &quot;as the LORD lives&quot; sworn in these three qualities is the oath the nations will one day swear sincerely (Isa 45:23; Rom 14:11) — a promise fulfilled as Christ draws the nations to himself.</p>",
"3": "<p>&quot;Break up your untilled ground and do not sow among thorns.&quot; Jesus&apos;s parable of the sower (Matt 13:3-9) takes up this exact agricultural metaphor: the rocky, thorny ground that chokes the seed is the untilled, uncircumcised heart. The preparation of the soil corresponds to the work of the Spirit that precedes repentance. Christ himself is the sower who comes to sow the word; the call of Jer 4:3 is realized when the word of the kingdom takes root.</p>",
"4": "<p><strong>Circumcise your hearts</strong> — the inner circumcision that Deuteronomy 10:16 and 30:6 anticipate. Paul reads this trajectory in Romans 2:28-29: &quot;A person is not a Jew who is one outwardly... circumcision is of the heart, by the Spirit, not by the written code.&quot; Colossians 2:11-12 identifies this heart-circumcision with baptism into Christ&apos;s death and resurrection — the circumcision &quot;not done by human hands.&quot; Christ performs the true circumcision Jeremiah demands: the cutting away of the old nature through his cross.</p>",
"5": "<p>The trumpet-call to gather in the fortified cities sounds the alarm of approaching judgment. Matthew 24:31 and 1 Corinthians 15:52 use the same trumpet-and-gathering imagery for Christ&apos;s return — not to flee into cities but to gather the elect. The same alarm that signals judgment here becomes the signal of final redemption when Christ sounds his trumpet. The gathered remnant finds their city not in Zion&apos;s fortifications but in Christ himself (Heb 12:22-24).</p>",
"6": "<p>&quot;Raise the signal flag toward Zion; flee to safety.&quot; The signal flag (<em>nēs</em>) lifted toward Zion becomes in Isaiah&apos;s vision the banner around which the nations gather (Isa 11:10, 12) — and Paul identifies this banner with Christ (Rom 15:12). The escape flag that here signals imminent doom becomes in Christ the rallying point for final rescue. The one who was lifted up (John 12:32 — &quot;I, when I am lifted up, will draw all people to myself&quot;) is the ultimate signal toward which all nations flee for safety.</p>",
"7": "<p>&quot;The lion has come out of his thicket, and the destroyer of nations has set out.&quot; The coming destroyer is YHWH&apos;s instrument of judgment (Babylon). Christ enters this picture as the one who absorbs the destroyer&apos;s blow rather than routing it away: he stands in the path of the lion and is struck (cf. 1 Pet 5:8 — the adversary prowls like a roaring lion; Christ has already defeated this roar, 1 Cor 15:55). The city laid waste in Jeremiah&apos;s day anticipates the city Christ redeems at final cost.</p>",
"8": "<p>&quot;Put on sackcloth and wail and howl; for the fierce anger of the LORD has not turned back.&quot; The divine wrath that has not turned back in Jeremiah&apos;s generation was absorbed — not turned back — in the death of Christ. The anger settled fully on him (Rom 3:25; 1 John 2:2): at Calvary the anger is finally and finally satisfied rather than merely postponed. The mourning of Jeremiah 4:8 finds its resolution in the mourning of those who look on the one they have pierced (Zech 12:10) — mourning that turns to eschatological comfort.</p>",
"9": "<p>&quot;The king&apos;s courage will fail, along with the courage of the officials and the priests.&quot; Every human institution of leadership fails before the final judgment. Christ is the King whose courage did not fail — who &quot;set his face like flint&quot; (Isa 50:7) toward Jerusalem and the cross. He is also the great High Priest who entered the most holy place not trembling but with full access (Heb 4:14-16; 10:19-22). Where Judah&apos;s kings and priests lose heart, Christ holds the priestly-kingly office with unwavering resolve.</p>",
"10": "<p>&quot;You have truly deceived this people.&quot; Jeremiah&apos;s protest that the false peace-promises constituted a divine deception is his boldest complaint. Christ does not deceive: he is the truth (John 14:6), and his warnings are always fully honest (Matt 24:4 — &quot;See that no one deceives you&quot;). He bore the consequences of the deceptions Israel experienced — taking the judgment that came because they believed lies — while himself speaking only truth. His integrity under false accusation (Mark 14:55-59) is the antithesis of the false promises Jeremiah protests.</p>",
"11": "<p>&quot;A scorching wind from the bare heights in the desert — not to winnow and not to cleanse.&quot; A wind of pure judgment, not the productive wind of harvest. The Spirit comes in wind (Acts 2:2 — &quot;a sound like the rushing of a mighty wind&quot;) and his wind is for cleansing and new creation, not destruction. Christ sends the purifying Spirit where the scorching judgment-wind of Jer 4:11 would have destroyed; the same divine breath that consumes opposition becomes life-giving wind for those who are in Christ.</p>",
"12": "<p>YHWH pronounces judgment through the scorching wind. The language of judicial pronouncement — &quot;now I will pronounce judgment against them&quot; — is the language of the last assize. Christ is the judge before whom all such judgments reach their final form (John 5:22 — the Father has given all judgment to the Son). The partial judgments of history (Babylon against Jerusalem) are anticipatory verdicts that point to the comprehensive final judgment Christ pronounces.</p>",
"13": "<p>&quot;Look — he advances like storm clouds; his chariots are like a whirlwind.&quot; The terrifying advance of Babylon; yet Revelation 19:11 depicts Christ himself riding out on a white horse with the armies of heaven. The imagery of the advancing warrior-judge that Babylon embodies in judgment becomes, at the end, the very image of Christ as the final judge whose coming cannot be stopped. The storm-cloud advance terrifies those outside covenant; for those in Christ it is his appearing in glory (Titus 2:13).</p>",
"14": "<p><strong>&quot;O Jerusalem, wash the evil from your heart.&quot;</strong> The washing Christ provides is not moral effort but the blood that cleanses: 1 John 1:7 — &quot;the blood of Jesus, his Son, purifies us from all sin.&quot; Titus 3:5 speaks of the &quot;washing of rebirth and renewing by the Holy Spirit.&quot; The call of Jer 4:14 (wash!) is answered by Christ&apos;s atoning work: he provides what the imperative demands. The one who said &quot;unless I wash you, you have no part with me&quot; (John 13:8) supplies the washing the heart cannot perform on itself.</p>",
"15": "<p>The herald voices from Dan and Mount Ephraim — the northern border — announce that judgment is approaching from the direction of Babylon. These are the watchmen of impending doom. Christ is the final herald-prophet announcing not coming judgment but accomplished salvation and impending consummation. His proclamation in Luke 4:18 (&quot;the Spirit of the Lord is on me, to proclaim good news&quot;) is the last and greatest herald-voice that answers the herald-voices of Jeremiah&apos;s day.</p>",
"16": "<p>The besiegers announced to the nations — Jerusalem is surrounded. The nations who &quot;hear&quot; this as spectators of judgment eventually become, in Christ, participants in Jerusalem&apos;s salvation (Eph 2:12-13 — those who were once &quot;foreigners to the covenants of the promise&quot; are now brought near). The nations who watched Babylon besiege Jerusalem anticipate the nations who through Christ are grafted into the covenant city (Rev 21:24-26).</p>",
"17": "<p>&quot;Like guards surrounding a field, so they surround her on every side, because she has rebelled against me.&quot; The siege as covenant judgment — rebellion brings encirclement. Christ bore the ultimate encirclement: surrounded by his enemies at Gethsemane and Golgotha, he experienced the siege that covenant rebellion deserved. His death in the surrounded city (Jerusalem) absorbs the covenant curse of encirclement (Deut 28:52) on behalf of those he rescues.</p>",
"18": "<p>&quot;Your conduct and your actions have brought this on you.&quot; The covenant justice: the punishment fits the crime. Paul&apos;s principle in Galatians 6:7 (&quot;whatever a person sows, they will also reap&quot;) expresses the same theology. Christ enters this framework as the one who reaps what he did not sow — bearing the consequences of others&apos; conduct (Isa 53:4-5: &quot;he took up our pain and bore our suffering... the punishment that brought us peace was on him&quot;). He breaks the equation of Jer 4:18 by absorbing results he did not cause.</p>",
"19": "<p><strong>&quot;My anguish, my anguish! I writhe in pain!&quot;</strong> Jeremiah&apos;s visceral identification with the suffering of the people — the prophet&apos;s own body resonating with the nation&apos;s agony. This is one of the deepest anticipations of Christ&apos;s incarnational empathy. Luke 19:41 — Jesus &quot;wept over&quot; Jerusalem; John 11:35 — &quot;Jesus wept.&quot; The prophet who cannot keep silent in his anguish prefigures the Christ who weeps with those who weep (Rom 12:15) and whose suffering is not distant sympathy but physical identification. Hebrews 5:7 describes Jesus offering up &quot;loud cries and tears.&quot;</p>",
"20": "<p>&quot;Crash after crash — the whole land is laid waste; in a flash my tents are destroyed.&quot; The rapid collapse of everything — the speed of total loss. The eschatological dimension: 2 Peter 3:10 speaks of the heavens disappearing with a roar and the elements being destroyed. Christ addresses this instability with the promise that his word will never pass away (Matt 24:35) and that the final collapse of all earthly structures is not the end but the threshold of the new creation (Rev 21:1).</p>",
"21": "<p>&quot;How long must I see the battle standard and hear the blare of the trumpet?&quot; The prophet&apos;s lament at the unending warfare. Revelation uses both battle-standard and trumpet extensively for the end-time sequence (Rev 8-11, trumpet judgments; Rev 19, the war). Christ&apos;s &quot;how long&quot; language appears in Mark 9:19 (&quot;how long shall I put up with you?&quot;) — the same divine frustration at human faithlessness that runs through Jeremiah. His coming answers the &quot;how long&quot; of all Jeremianic lament.</p>",
"22": "<p>&quot;My people are foolish — they do not know me; they are clever at doing evil.&quot; This is the inversion that Paul diagnoses in 1 Corinthians 1:25: &quot;the foolishness of God is wiser than human wisdom.&quot; The people who are stupid about good and clever about evil are saved by one who appears foolish by their standards — the crucified Christ who confounds the clever (1 Cor 1:27-29). Christ is the wisdom of God (1 Cor 1:30) who replaces the false cleverness of those who do not know YHWH.</p>",
"23": "<p><strong>&quot;I looked at the earth and it was <em>tōhû wābōhû</em> — formless and void.&quot;</strong> The deliberate reversal of Genesis 1:2 — the uncreation of the ordered world through covenant violation. The same vocabulary makes this the most theologically charged vision in Jeremiah: sin undoes creation. Christ&apos;s redemption is explicitly new-creation language: &quot;if anyone is in Christ, the new creation has come; the old has gone, the new is here&quot; (2 Cor 5:17). The <em>tōhû wābōhû</em> of judgment is answered by the new creation of resurrection.</p>",
"24": "<p>The quaking mountains and swaying hills — creation destabilized by the weight of divine judgment. Hebrews 12:26-28 quotes the Sinai earthquake (&quot;I will shake not only the earth but also the heavens&quot;) and applies it to the final shaking that removes what can be shaken, leaving only the unshakeable kingdom. Christ is the one who stands unshaken while all else falls, and those in him share his unshakeable ground. The mountains that quake in Jer 4:24 yield ultimately to the mountain that cannot be moved — Zion in its eschatological form (Heb 12:22).</p>",
"25": "<p>&quot;I looked — there was no human being, and all the birds of the sky had flown away.&quot; Total depopulation — the reversal of Genesis 1:20-28 (birds created, humanity mandated to fill the earth). The cosmic scope of judgment mirrors the cosmic scope of the image of God in humanity: when humanity falls, creation falls with it (Rom 8:20-22 — creation subjected to futility because of human sin). Christ as the last Adam (1 Cor 15:45) restores the human vocation and with it creation&apos;s glory.</p>",
"26": "<p>&quot;The fertile land was a desert; all its cities lay in ruins before the LORD.&quot; The Carmel become wilderness — the covenantal reversal of blessing to curse (Deut 28:23-24). Christ restores this reversal: Isaiah 35 (wilderness blooming) is Jesus&apos;s own answer to John the Baptist&apos;s question (Matt 11:5 — &quot;the blind see, the lame walk, the dead are raised&quot;). His healings and the feeding of crowds in the wilderness are the signs that the wilderness-to-Carmel reversal has begun in him.</p>",
"27": "<p>&quot;Yet I will not make a complete end.&quot; The <em>kālâ</em>-clause — YHWH will not make a total annihilation. This remnant-guarantee within the judgment oracle is the theological hinge of the whole chapter. Paul quotes this verse directly in Romans 9:28 (&quot;the Lord will carry out his sentence on earth with speed and finality&quot;) in the context of arguing that not all Israel is lost — Christ preserves a remnant. The incomplete end that Jeremiah promises is the opening for redemption that Christ enters.</p>",
"28": "<p>&quot;For this the earth will mourn and the heavens above grow dark; for I have spoken, I have decided, and I will not turn back.&quot; The cosmic mourning of creation at covenant rupture. At the crucifixion, darkness covered the land from noon until three (Matt 27:45) and the earth shook (Matt 27:51) — creation itself responding to the death of the Son with the cosmic signs of covenant judgment being absorbed. The irreversible divine decree of Jer 4:28 is met by the equally irreversible divine decision of the cross.</p>",
"29": "<p>Every city abandoned; hiding in thickets and rocks. Revelation 6:15-17 describes the same flight — &quot;the kings of the earth, the princes, the generals... hid in caves and among the rocks of the mountains&quot; at the Lamb&apos;s wrath. The covering requested (Rev 6:16 — &quot;fall on us and hide us from the face of him who sits on the throne and from the wrath of the Lamb&quot;) is the very thing Christ provides for those who come to him — not hiding from the wrath but being sheltered within the one who absorbed it.</p>",
"30": "<p>&quot;Though you clothe yourself in crimson, though you adorn yourself with golden jewelry... you adorn yourself in vain&quot; — the futility of Jerusalem&apos;s self-beautification before judgment. The Bride of Revelation 19:7-8 is clothed not in her own crimson but in &quot;fine linen, bright and clean&quot; — &quot;the righteous acts of God&apos;s holy people.&quot; The clothing that adorns in vain in Jeremiah is replaced by the righteousness of Christ (2 Cor 5:21) that constitutes the true beauty of the eschatological bride.</p>",
"31": "<p><strong>&quot;The cry of Daughter Zion gasping, stretching out her hands: Woe to me, for I am fainting before killers!&quot;</strong> The birthing-cry and death-cry together — the city in extremis. The lament of Zion at her killers is the lament Christ hears and answers: Luke 23:28 — Jesus says to the daughters of Jerusalem, &quot;weep for yourselves and for your children.&quot; His death in Jerusalem takes the city&apos;s death-cry into himself; his resurrection is the city&apos;s cry answered with new life. Revelation 12:2 (the woman crying out in labor) takes up this cosmic birth-and-death imagery and resolves it in Christ&apos;s victory.</p>"
},
"5": {
"1": "<p><strong>&quot;If you can find one person who deals honestly and seeks truth, I will forgive Jerusalem.&quot;</strong> The decisive Christological verse of the chapter — the search for one righteous person. Abraham bargained for Sodom with ten (Gen 18:32); here YHWH requires only one. The search fails among all humans (cf. Eccl 7:28 — &quot;I found one upright man among a thousand... but not one upright woman among all these&quot;). Romans 3:10-12 declares &quot;there is no one righteous, not even one.&quot; Christ is the one exception the search finds: the single righteous one whose existence makes forgiveness possible (Rom 5:19 — &quot;through the obedience of the one man the many will be made righteous&quot;).</p>",
"2": "<p>&quot;Even when they say &apos;As the LORD lives,&apos; they are swearing falsely.&quot; The covenant oath invoked insincerely. Christ never swore falsely — Matthew 5:37: &quot;let your &apos;Yes&apos; be &apos;Yes&apos; and your &apos;No,&apos; &apos;No.&apos;&quot; He is described as &quot;the Amen, the faithful and true witness&quot; (Rev 3:14). The false oath-swearing that condemns Israel in Jeremiah is the exact failure Christ does not share — his perfect truthfulness is the ground on which the forgiveness Jer 5:1 seeks can be given.</p>",
"3": "<p>&quot;You struck them, but they felt nothing; you crushed them, but they refused correction.&quot; The ineffectual discipline — blows that harden rather than break. Christ alone truly &quot;felt&quot; the blow in both senses: Isa 53:4-5 — &quot;he took up our pain and bore our suffering... he was pierced for our transgressions, he was crushed for our iniquities.&quot; Where Israel refused correction by the strikes they received, Christ received strikes that were not his and absorbed them with full effect — his suffering accomplished what Israel&apos;s suffering refused to do.</p>",
"4": "<p>&quot;These are only the poor; they are ignorant; they do not know the way of the LORD.&quot; The charitable first explanation for covenant failure. Jesus was born among the poor and proclaimed good news to them (Luke 4:18; Matt 11:5). He taught the uneducated fishermen &quot;the way of the LORD&quot; that even the poor could grasp. The ignorance of the poor that Jeremiah excuses is the ignorance Christ addresses with his open-access teaching: &quot;the poor have the good news proclaimed to them.&quot;</p>",
"5": "<p>&quot;So I went to the leaders... but they too had broken the yoke and torn off the bonds.&quot; Both poor and great fail — the universal failure that Romans 3:9-12 systematizes (&quot;Jews and Gentiles alike are all under the power of sin... there is no one righteous, not even one&quot;). Christ stands outside this universal: he did not break the yoke (he took on the easy yoke, Matt 11:30) and he did not tear off the bonds of covenant obligation but fulfilled them entirely (Matt 5:17 — &quot;I have not come to abolish the Law or the Prophets but to fulfill them&quot;).</p>",
"6": "<p>Three attackers: lion, wolf, leopard — the threat intensifying. These images of destructive power become in the NT the adversarial forces Christ has overcome. 1 Peter 5:8 (the devil as prowling lion); John 10:12 (the wolf scattering the flock — the hireling runs but the Good Shepherd stays). Christ does not flee from the lion, wolf, or leopard but faces the spiritual powers they represent and at the cross &quot;disarmed the powers and authorities&quot; (Col 2:15).</p>",
"7": "<p>&quot;How can I forgive you for this?&quot; The question is rhetorical in Jeremiah — the violations are so comprehensive that forgiveness seems impossible. Romans 3:25-26 answers the question: God &quot;presented Christ as a sacrifice of atonement... so as to be just and the one who justifies those who have faith in Jesus.&quot; The apparent impossibility of forgiveness Jeremiah raises is resolved not by overlooking the sin but by the substitutionary atoning death that makes forgiveness both possible and just.</p>",
"8": "<p>&quot;They are like well-fed, lusty stallions — each neighing after another man&apos;s wife.&quot; The sexual appetite as metaphor for undiscriminating covenant infidelity. James 4:4 uses the same adultery-metaphor: &quot;you adulterous people, don&apos;t you know that friendship with the world means enmity against God?&quot; Christ calls the soul to exclusive covenant loyalty — the husband-wife exclusive love that runs through Jeremiah&apos;s imagery finds its fulfillment in Christ as the bridegroom (John 3:29; Eph 5:25-27) who makes the church his faithful bride.</p>",
"9": "<p>&quot;Should I not call them to account? Should I not take vengeance?&quot; The divine question of justice. Romans 12:19 — &quot;vengeance is mine, I will repay, says the Lord.&quot; Christ bears this judgment on behalf of the sinners who deserve it (1 Pet 2:24 — &quot;he himself bore our sins in his body on the cross&quot;). The divine vengeance demanded in Jer 5:9 was executed — not set aside — but it fell on the Son rather than destroying those in him. Justice is satisfied; mercy is provided.</p>",
"10": "<p>&quot;Advance through her vineyards and ravage them, but do not destroy them completely.&quot; The vine-ravaging that does not annihilate. John 15:1-2 — the Father as the gardener who removes unfruitful branches but does not destroy the vine itself. Christ as the true vine survives all pruning and ravaging; those who remain in him bear fruit even when the external evidence looks like catastrophe. The incomplete destruction of Jer 5:10 reflects the remnant-principle that Christ embodies as the indestructible vine.</p>",
"11": "<p>&quot;The house of Israel and the house of Judah have acted completely faithlessly toward me.&quot; The comprehensive covenant failure of both kingdoms. Christ is the faithful Israel — the one who did not act faithlessly. Matthew 3:15: &quot;it is proper for us to do this to fulfill all righteousness.&quot; Where both houses failed at every point, Christ fulfills every obligation as the faithful covenant partner. His faithfulness covers the unfaithfulness; he is the representative faithful Israelite (Gal 3:16 — &quot;the promises were spoken to Abraham and to his seed... meaning one person, who is Christ&quot;).</p>",
"12": "<p>&quot;He will do nothing; no disaster will come upon us.&quot; The denial of divine judgment — the practical atheism that ignores YHWH&apos;s announced intentions. 2 Peter 3:3-4 describes the same scoffing in the last days: &quot;Where is this &apos;coming&apos; he promised?&quot; Christ&apos;s return will vindicate all the prophets&apos; warnings that were denied — including Jeremiah&apos;s. The denial of Jer 5:12 is the prototype of the denial of Christ&apos;s return that Peter warns against.</p>",
"13": "<p>&quot;The prophets are nothing but wind; the word of God is not in them.&quot; The accusation against the true prophets by those who prefer the false ones. Jesus warned of the same reversal (Matt 7:15 — &quot;beware of false prophets&quot;; Matt 7:22-23 — &quot;Lord, Lord, did we not prophesy in your name?&quot;). Christ is himself the Word of God (John 1:1) — the word that the accusers of Jer 5:13 denied was in the true prophets is the word made flesh in Christ. He vindicates the true word by being the ultimate prophet.</p>",
"14": "<p>&quot;I will make my words in your mouth a fire, and this people the wood, and it will consume them.&quot; The divine word as consuming fire. Hebrews 4:12 — &quot;the word of God is alive and active, sharper than any two-edged sword.&quot; Christ is identified as the Word (John 1:1) and the one whose eyes are like &quot;blazing fire&quot; (Rev 1:14; 19:12). The fire-word of Jer 5:14 — the word that judges and consumes — is the same word that, in Christ, also creates and purifies (Luke 12:49 — &quot;I have come to bring fire on the earth&quot;).</p>",
"15": "<p>&quot;I am bringing a nation against you from far away... an ancient nation, an enduring nation, whose language you do not know.&quot; The incomprehensible foreign aggressor as instrument of judgment. In Acts 2:4-11, the gift of tongues reverses the linguistic barrier — nations that spoke incomprehensible languages to each other now hear the mighty acts of God in their own tongues. What was a judgment-sign (unintelligible language of the invader) becomes a blessing-sign (the Spirit-given languages of Pentecost), both occurring in Jerusalem.</p>",
"16": "<p>&quot;Their quivers are like open graves; they are all mighty men.&quot; Paul quotes similar language from the Psalms in Romans 3:13 (&quot;their throats are open graves&quot;) as part of the catena proving universal human sinfulness. The arrows that kill from open-grave quivers represent the power of death that Christ has defeated (1 Cor 15:55 — &quot;where, O death, is your victory?&quot;; Rev 6:8 — Death and Hades as powers ridden by the pale horse, but ultimately thrown into the lake of fire, Rev 20:14).</p>",
"17": "<p>The nation devours everything — harvest, food, sons and daughters, flocks, vines, fig trees, fortified cities. The comprehensive devouring of Israel&apos;s blessings anticipates the restoration promise in Joel 2:25 — &quot;I will repay you for the years the locusts have eaten.&quot; Christ&apos;s ministry of provision (feeding thousands in the wilderness, John 6:35 — &quot;I am the bread of life&quot;) is the reversal of this devouring — he who is the true harvest cannot be consumed but gives himself as inexhaustible food.</p>",
"18": "<p>&quot;Yet even in those days I will not make a complete end of you.&quot; The remnant-promise repeated (cf. 4:27). Romans 9:27-29 quotes Isaiah&apos;s remnant-theology alongside Jeremiah&apos;s in arguing that God&apos;s word has not failed — a remnant is saved. Christ is the true remnant, the single righteous one (5:1) in whom the remnant-promise finds its fullest form. Those who are &quot;in Christ&quot; share his remnant-status: they are the complete end that was not made because of him.</p>",
"19": "<p>&quot;As you abandoned me and served foreign gods in your own land, so you will serve foreigners in a land not your own.&quot; The covenant curse of service-reversal: from serving YHWH to serving foreign gods, from your land to a foreign land. Christ reverses this: Galatians 4:4-5 — &quot;God sent his Son... to redeem those under the law, that we might receive adoption to sonship.&quot; The service-reversal of Jeremiah&apos;s curse is answered by Christ&apos;s redemption that restores sonship (not servitude) and inheritance (not exile).</p>",
"20": "<p>The announcement to all of Jacob and Judah — the proclamation that encompasses both houses. Christ&apos;s gospel is also announced to the whole house: Romans 1:16 — &quot;the power of God... first to the Jew, then to the Gentile.&quot; The same word that announced judgment to all Jacob in Jeremiah is the word of the gospel that goes to all Jacob&apos;s descendants and beyond — the announcement-structure of Jer 5:20 is the structure of apostolic proclamation.</p>",
"21": "<p><strong>&quot;You foolish and senseless people — you have eyes but do not see; you have ears but do not hear.&quot;</strong> Jesus quotes Isaiah 6:9-10 (the same tradition as Jeremiah 5:21) in explaining why he speaks in parables (Matt 13:13-15) — and then he opens the disciples&apos; eyes. His healings of the blind (Mark 8:22-26; John 9) are enacted answers to this verse: where the whole nation had eyes that did not see, Christ restores sight both physically and spiritually. The deaf-ear that cannot hear the word is opened by the one whose own ears were perfectly attuned to the Father (John 5:30).</p>",
"22": "<p><strong>&quot;Should you not fear me? Should you not tremble before me? I am the one who set the sand as the boundary for the sea, as an eternal limit it cannot cross.&quot;</strong> The Creator who set the sea&apos;s limit is the God incarnate who commands the sea directly — Mark 4:39: &quot;he rebuked the wind and said to the waves, &apos;Quiet! Be still!&apos;&quot; And the disciples asked, &quot;Who is this? Even the wind and the waves obey him!&quot; (Mark 4:41). The one who made the sea&apos;s boundary in creation sets it again in a single word. Fear of YHWH (Jer 5:22) and wonder at Christ (Mark 4:41) are the same response.</p>",
"23": "<p>&quot;But this people has a stubborn, rebellious heart.&quot; The stubborn heart (<em>sōrēr</em>) is the same diagnosis as Ezekiel 36:26 — &quot;I will remove from you your heart of stone and give you a heart of flesh.&quot; Christ performs this surgery through the Spirit: 2 Corinthians 3:3 — &quot;you are a letter... written not with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts.&quot; The stubborn, rebellious heart of Jer 5:23 is the heart Christ transforms through his new covenant work.</p>",
"24": "<p>&quot;They do not even say in their hearts, &apos;Let us fear the LORD our God, who gives the autumn and spring rains.&quot; The failure to recognize the Creator in his creation-gifts. James 5:7 uses the same rain-agriculture imagery for patience: &quot;the farmer waits for the land to yield its valuable crop, patiently waiting for the autumn and spring rains.&quot; And James 5:8 — &quot;You too, be patient and stand firm, because the Lord&apos;s coming is near.&quot; Christ is the giver of the rains (as YHWH) and the object of patient waiting (as the returning Lord).</p>",
"25": "<p>&quot;Your iniquities have diverted these good things, and your sins have kept them from you.&quot; Sin as a barrier to covenant blessing — what was meant to flow is dammed by iniquity. Christ removes the barrier: Romans 5:1-2 — &quot;since we have been justified through faith, we have peace with God... and we rejoice in the hope of the glory of God.&quot; The access (prosagōgē) that sin had blocked is restored in Christ. The rain withheld because of sin flows again when the sin-barrier is removed at the cross.</p>",
"26": "<p>&quot;Among my people there are wicked men — they lurk like hunters who set traps.&quot; The predatory exploitation of the vulnerable within the covenant community. Jesus describes the same predation in Matthew 23:14 (those who devour widows&apos; houses) and in Luke 4:18 (his mission is to set the oppressed free). His parable of the unmerciful servant (Matt 18:23-35) — the one forgiven much who refuses to forgive little — describes the same predatory wickedness within the community of grace that Jeremiah indicts.</p>",
"27": "<p>&quot;As a cage is full of birds, so their houses are full of goods gotten by deceit.&quot; The accumulated wealth of exploitation — the cage-full of stolen abundance. Luke 12:16-21 (the parable of the rich fool) and Luke 16:19-31 (the rich man and Lazarus) are Christ&apos;s parables of ill-gotten wealth with the same verdict as Jer 5:27-28. The cage-full of fraudulently obtained goods in Jeremiah corresponds to the barns full of grain in the parable — and the same divine verdict applies: &quot;You fool! This very night your life will be demanded from you.&quot;</p>",
"28": "<p>&quot;They do not defend the rights of the poor; they do not plead the cause of the needy.&quot; The failure of social covenant justice — the very criterion of true religion (Isa 1:17; Mic 6:8). James 1:27 — &quot;religion that God our Father accepts as pure and faultless is this: to look after orphans and widows.&quot; Christ&apos;s announcement in Matthew 25:45 — &quot;whatever you did not do for the least of these, you did not do for me&quot; — is the final judgment on the failure Jeremiah describes. Christ is both the ultimate Judge who asks the question and, in the poor, the one whose cause is not defended.</p>",
"29": "<p>&quot;Should I not take vengeance on a nation such as this?&quot; The divine justice-question, repeated from v.9. Paul&apos;s answer (Rom 3:25-26): God presented Christ as the mercy seat — he demonstrated his justice by not letting sin go unpunished (Christ bore the punishment) and demonstrated his mercy by providing righteousness to those who trust in Jesus. The divine vengeance of Jer 5:29 is satisfied; the divine mercy of the gospel is simultaneously established. Christ resolves the justice-mercy tension the question raises.</p>",
"30": "<p>&quot;A horrible and shocking thing has occurred in the land.&quot; The summary introduction before the false-prophets indictment of v.31. The same shock vocabulary — &quot;horrible thing&quot; — marks the ultimate horror in the crucifixion narrative: the death of the Son of God is the most horrible and shocking thing that has occurred. Yet that horror becomes the source of salvation. The shocking things of covenant history accumulate toward the final shocking event of the cross.</p>",
"31": "<p><strong>&quot;The prophets prophesy what is false, the priests exercise authority on their own terms, and my people love it this way.&quot;</strong> The collapse of the prophetic and priestly offices into self-serving corruption — and the people&apos;s complicity in preferring comfortable lies. Jesus speaks to this directly: Matthew 7:15-23 — false prophets in sheep&apos;s clothing; &quot;I never knew you.&quot; He is the true Prophet (Deut 18:15-18; Acts 3:22) who speaks only what the Father tells him (John 12:49) and the true Priest who does not serve on his own terms but was appointed by YHWH (Heb 5:4-6). He replaces the corrupt prophetic and priestly offices with his own perfect double-ministry.</p>"
},
"6": {
"1": "<p>&quot;Flee to safety, people of Benjamin — get out of Jerusalem!&quot; Jesus gives the same command in Matthew 24:15-18 — &quot;when you see the abomination of desolation... let those who are in Judea flee to the mountains.&quot; He reads Jeremiah&apos;s warning pattern into his own eschatological discourse. The call to flee Jerusalem before divine judgment is a consistent prophetic theme that Jesus inherits and applies to the coming AD 70 destruction — and ultimately to the final judgment from which there is refuge only in Christ himself.</p>",
"2": "<p>&quot;I will destroy the fair and delicate Daughter Zion.&quot; The coming destruction of the city is what provoked Jesus&apos;s tears: Luke 19:41-44 — &quot;as he approached Jerusalem and saw the city, he wept over it and said... the days will come upon you when your enemies will build an embankment against you.&quot; Christ weeps over the destruction that Jeremiah&apos;s oracle announces — he sees what is coming and mourns rather than merely predicts. His compassion over Daughter Zion&apos;s destruction (Matt 23:37 — &quot;how often I have longed to gather your children together&quot;) is the divine grief made visible in his person.</p>",
"3": "<p>&quot;Shepherds with their flocks will come to her... each will pasture his flock.&quot; The enemy shepherds who come to consume Jerusalem rather than tend her. Jesus is the Good Shepherd who comes not to consume but to give his life for the sheep (John 10:11). The sheep entrusted to him will not be devoured by these encircling shepherd-destroyers: &quot;I give them eternal life, and they shall never perish; no one will snatch them out of my hand&quot; (John 10:28). The menacing shepherds of Jer 6:3 are answered by the protective shepherd of John 10.</p>",
"4": "<p>&quot;Alas for us, for the day is fading — the evening shadows are lengthening.&quot; The urgency of the fading day — time running out for repentance and escape. John 9:4 — Jesus said, &quot;as long as it is day, we must do the works of him who sent me. Night is coming, when no one can work.&quot; Christ is both the one who works while daylight remains and the one who is the light itself (John 8:12). The fading day of Jer 6:4 is answered by the coming of the light that darkness cannot overcome (John 1:5).</p>",
"5": "<p>&quot;Let us rise up and attack by night and demolish her fortified towers.&quot; The night attack on Jerusalem&apos;s defenses. Ephesians 6:12 — &quot;our struggle is not against flesh and blood, but against the rulers, against the authorities, against the powers of this dark world.&quot; The night-attack imagery of Jeremiah&apos;s military oracle becomes in Paul&apos;s framework the spiritual warfare that Christ has already won: Colossians 2:15 — &quot;having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross.&quot;</p>",
"6": "<p>&quot;Cut down trees and build a siege ramp against Jerusalem.&quot; The tree-cutting for military engineering. The cross of Christ is both a tree cut down for destruction (the Romans&apos; instrument of execution) and the tree of life: Acts 5:30 — &quot;the God of our ancestors raised Jesus from the dead — whom you killed by hanging him on a cross (<em>tree</em>).&quot; Galatians 3:13 — &quot;Christ redeemed us from the curse of the law by becoming a curse for us, for it is written: &apos;Cursed is everyone who is hung on a pole/tree.&apos;&quot; The siege-ramp tree of Jeremiah becomes the salvific tree of the cross.</p>",
"7": "<p>&quot;As a well keeps pouring out water, so she keeps pouring out wickedness.&quot; The ceaseless production of evil — sin as a spring that never runs dry. Christ transforms this image: at the Samaritan well (John 4:13-14), he offers water that becomes a spring inside the believer, welling up to eternal life. Where Jerusalem&apos;s well pours out wickedness without ceasing, Christ plants in believers a spring of life that pours out righteousness without ceasing. The same well-imagery, inverted.</p>",
"8": "<p>&quot;Take warning, O Jerusalem, or I will turn away from you.&quot; The withdrawal of divine presence as the ultimate sanction — worse than destruction. Christ is the fullness of divine presence: Matthew 28:20 — &quot;I am with you always, to the very end of the age.&quot; The warning &quot;I will turn away&quot; that Jerusalem failed to heed is answered by Christ&apos;s promise never to withdraw his presence from those who are his. Even his cry of desolation (Matt 27:46 — &quot;My God, my God, why have you forsaken me?&quot;) is not his turning away from us but his bearing our forsakenness.</p>",
"9": "<p>&quot;Carefully glean the remnant of Israel as a vinedresser gleans the vine — pass your hand over the branches again.&quot; The painstaking gleaningthat saves what can be saved. Luke 15:4-7 (the shepherd leaving ninety-nine to find one lost sheep) and Luke 15:8-10 (the woman searching every corner for the lost coin) enact this painstaking care. Christ is the gleanerof the remnant — he searches carefully, hand passing over branch by branch, to find and preserve each one. His attention to the individual (Zacchaeus, the woman with the hemorrhage) is this gleaning made personal.</p>",
"10": "<p>&quot;Their ears are closed — they cannot listen; the word of the LORD has become an offense to them.&quot; The stopped ear as covenant failure. Jesus quotes Isaiah 6:9-10 in Matthew 13:14-15 to explain why the word comes as parables — to those whose ears are closed, the parable adds to the closure; to those who hear, it opens further. Paul uses the same Isaiah text in Acts 28:26-27 at the close of his ministry to explain Jewish rejection of the gospel. 1 Corinthians 1:23 — &quot;the word of the cross is an offense (<em>skandalon</em>)&quot; — Christ himself is the offense that Jer 6:10 anticipates.</p>",
"11": "<p>&quot;I am full of the LORD&apos;s fury, worn out with holding it in.&quot; Jeremiah exhausted by containing the divine wrath he must proclaim. Christ at Gethsemane: &quot;my soul is overwhelmed with sorrow to the point of death&quot; (Matt 26:38); &quot;if it is possible, let this cup pass from me&quot; (Matt 26:39). The cup of divine fury that wore out Jeremiah in its proclaiming was the cup Christ drank in its fullness. He bore the wrath Jeremiah was only asked to announce — the prophet&apos;s exhaustion at holding it in was answered by Christ&apos;s exhaustion at drinking it down.</p>",
"12": "<p>&quot;Their houses will be given to others, along with their fields and wives, because I will stretch out my hand against the inhabitants.&quot; The expropriation of what was promised — the covenant reversal where blessings become curses. Jesus uses the same expropriation image in the parable of the tenants (Matt 21:33-41) — &quot;the kingdom of God will be taken away from you and given to a people who will produce its fruit.&quot; The stretched-out hand of YHWH&apos;s judgment that takes the vineyard from unfaithful tenants gives it to those who receive Christ as the cornerstone (Matt 21:42).</p>",
"13": "<p>&quot;From the least to the greatest, all are greedy for dishonest gain; from prophet to priest, all practice deceit.&quot; The comprehensive moral corruption that runs through every social level. Matthew 23 contains Jesus&apos;s sustained denunciation of the same pattern in his own generation — scribes and Pharisees who make long prayers and devour widows&apos; houses (Matt 23:14), who travel across land and sea to make a single convert and make them twice as much a son of hell. The greedy-for-gain leaders of Jer 6:13 are the whitewashed tombs of Matt 23:27.</p>",
"14": "<p><strong>&quot;They heal the wound of my people as though it were minor, saying &apos;Peace, peace,&apos; when there is no peace.&quot;</strong> The false prophets&apos; cosmetic treatment of a mortal wound. Christ announces the real peace that costs everything: Ephesians 2:14-16 — &quot;he himself is our peace, who has made the two groups one and has destroyed the barrier... making peace through his blood, shed on the cross.&quot; Colossians 1:20 — &quot;through him to reconcile to himself all things... by making peace through his blood.&quot; The peace the false prophets offered cheaply, Christ provides through the only means that genuinely heals: his own sacrifice.</p>",
"15": "<p>&quot;Are they ashamed of their detestable conduct? No, they have no shame at all; they do not even know how to blush.&quot; The seared conscience — the loss of moral self-awareness. Paul describes the same in Romans 1:32 (&quot;they not only continue to do these very things but also approve of those who practice them&quot;) and in 1 Timothy 4:2 (&quot;whose consciences have been seared as with a hot iron&quot;). Christ does not provide a solution to seared conscience through moral lecturing but through the new heart (Jer 31:33) and the Spirit of conviction (John 16:8 — &quot;when he comes, he will prove the world to be in the wrong about sin and righteousness and judgment&quot;).</p>",
"16": "<p><strong>&quot;Stand at the crossroads and look; ask for the ancient paths, ask where the good way is, and walk in it, and you will find rest for your souls.&quot;</strong> The most directly Christological verse of the chapter. Jesus says in Matthew 11:28-30: &quot;Come to me, all you who are weary and burdened, and I will give you rest... and you will find rest for your souls.&quot; He uses the exact phrase of Jer 6:16 (<em>mānôaḥ lĕnapšôtêkem</em> → <em>anapausin tais psuchais humōn</em>, LXX → Matt 11:29). The &quot;ancient paths&quot; and &quot;good way&quot; are not a path but a Person — Christ himself says &quot;I am the way&quot; (John 14:6). The invitation of Jer 6:16 is fulfilled and personified in Christ&apos;s own invitation.</p>",
"17": "<p>&quot;I appointed watchmen over you and said, &apos;Listen to the sound of the trumpet!&apos; But they said, &apos;We will not listen.&apos;&quot; The refusal of the watchman&apos;s warning. Christ is the ultimate watchman (Ezek 33:7-9 identifies the prophet as watchman; Jesus inherits this role). The sound of his trumpet-call (Matt 24:31; 1 Thess 4:16) will not be refused at his return as it was in Jeremiah&apos;s day. His parables of watchfulness (Matt 25:1-13, the ten virgins; Matt 25:14-30, the talents) are his insistence that the watchman&apos;s warning must now be heeded before the final trumpet sounds.</p>",
"18": "<p>&quot;Therefore, you nations, hear; you witnesses, know what has happened among them.&quot; The nations called as witnesses to Israel&apos;s covenant failure. Paul uses Israel&apos;s failure as the occasions for Gentile inclusion: Romans 11:11 — &quot;salvation has come to the Gentiles to make Israel envious.&quot; The nations who in Jeremiah are called to witness judgment become in Christ the nations called to receive salvation. The judgment-witness address of Jer 6:18 anticipates the Great Commission witness-address of Matthew 28:19 — all nations, now not as spectators of judgment but as recipients of grace.</p>",
"19": "<p>&quot;Listen, O earth: I am going to bring disaster on this people — the direct result of their own schemes.&quot; The earth called to hear as a legal witness (Deut 32:1; Mic 1:2). Romans 8:19-22 describes the earth as groaning in frustrated expectation — not merely as a legal witness but as a participant in the fall that human sin caused. Christ&apos;s redemption includes creation&apos;s liberation: &quot;creation itself will be liberated from its bondage to decay and brought into the freedom and glory of the children of God&quot; (Rom 8:21). The earth called to witness judgment in Jer 6:19 will witness liberation in Christ&apos;s consummation.</p>",
"20": "<p><strong>&quot;What good is it if incense is brought from Sheba and fragrant cane from a distant land? Your burnt offerings are not acceptable; your sacrifices do not please me.&quot;</strong> The total inadequacy of ritual offerings without covenant faithfulness. Hebrews 10:5-10 (citing Ps 40:6-8) — &quot;sacrifice and offering you did not desire, but a body you prepared for me... I have come to do your will, O God.&quot; Christ is the offering that is acceptable — not because it is more expensive than Sheba&apos;s incense but because it is the body-offering of perfect obedience. He replaces the unacceptable offerings with himself as the one truly pleasing sacrifice (Eph 5:2 — &quot;a fragrant offering and sacrifice to God&quot;).</p>",
"21": "<p>&quot;I am going to put obstacles before this people, and they will stumble over them.&quot; The obstacles of divine judgment. Paul and Peter both identify Christ himself as the stumbling stone: Romans 9:33 (&quot;I lay in Zion a stone that causes people to stumble... and the one who trusts in him will never be put to shame&quot;) and 1 Peter 2:8 (&quot;a stone that causes people to stumble... they stumble because they disobey the message&quot;). The divine obstacle of Jer 6:21 that trips the disobedient becomes in Christ the cornerstone that builds up the obedient (1 Pet 2:6-7).</p>",
"22": "<p>&quot;Look, an army is coming from the northern country, a great nation is being stirred up from the ends of the earth.&quot; The northern invader approaching. Revelation 19:11-16 depicts Christ himself leading the armies of heaven at his return — and his coming from heaven is described with the imagery of the conquering warrior that Jeremiah&apos;s northern-army oracle anticipates. The terror of the approaching army that Jer 6:22 inspires becomes the longing-for-return of those who watch for Christ&apos;s coming (Rev 22:20 — &quot;come, Lord Jesus&quot;).</p>",
"23": "<p>&quot;They are armed with bow and spear; they are ruthless and without mercy. They sound like the roaring sea.&quot; The invincible, merciless enemy army. Christ faces the ultimate merciless enemies — sin, death, and the spiritual powers — with the same ruthlessness directed against himself: &quot;he was pierced for our transgressions, he was crushed for our iniquities&quot; (Isa 53:5). The &quot;roaring sea&quot; imagery connects to the demonic (Mark 5:13 — the swine herd into the sea) that Christ also vanquishes. His resurrection is the defeat of the merciless enemy: death swallowed up in victory (1 Cor 15:54).</p>",
"24": "<p>&quot;We have heard the report — our hands go limp; distress has seized us, pain like a woman in labor.&quot; The paralysis of terror before the approaching judgment. Jesus uses the labor-pains image for the eschatological tribulation (Matt 24:8 — &quot;all these are the beginning of birth pains&quot;; John 16:21-22 — the woman in labor whose pain turns to joy). The labor-pain distress of Jer 6:24 is reframed by Christ as the birth-pain of the new creation — the anguish is real but purposeful, leading to joy that the world cannot take away (John 16:22).</p>",
"25": "<p>&quot;Do not go out into the fields or walk along the roads, for the enemy has a sword; terror is on every side.&quot; Complete confinement — the city besieged, nowhere safe. Christ is the one to whom we flee when no external place is safe: Colossians 3:3 — &quot;your life is now hidden with Christ in God.&quot; The terror on every side of Jer 6:25 is answered not by a safe geographical refuge but by the person of Christ as the hiding-place: Psalm 27:5 (&quot;in the day of trouble he will keep me safe in his dwelling&quot;) finds its fullest form in being &quot;in Christ&quot; (the most frequent Pauline phrase for salvation).</p>",
"26": "<p><strong>&quot;Mourn as for an only son, a bitter lamentation.&quot;</strong> The mourning for an only son — the deepest possible grief in the ancient Near East. Zechariah 12:10 uses exactly this language for Israel&apos;s future mourning over &quot;the one they have pierced... they will mourn for him as one mourns for an only child.&quot; John 19:37 quotes Zechariah 12:10 at the crucifixion. Christ&apos;s death is the death of the only Son (John 3:16 — &quot;he gave his one and only Son&quot;) — the mourning Jer 6:26 calls for is fulfilled at the cross, and the mourning turns to resurrection joy (John 16:20-22).</p>",
"27": "<p>&quot;I have made you an assayer and a tester among my people, so that you may know and test their conduct.&quot; Jeremiah as the divine quality-tester — measuring the metal of the community&apos;s faithfulness. Christ is the ultimate assayer: Malachi 3:3 — &quot;he will sit as a refiner and purifier of silver.&quot; 1 Corinthians 3:13 — &quot;the fire will test the quality of each person&apos;s work.&quot; His word is the fire (Jer 5:14; Heb 4:12) that reveals what is true metal and what is dross. He tests not to reject but to refine — those who pass through the fire come out purified (1 Pet 1:7).</p>",
"28": "<p>&quot;They are all rebellious troublemakers... they are bronze and iron — utterly corrupt.&quot; The material metaphors for hardened, unrefined character. Bronze and iron are harder than silver — they resist the refiner&apos;s fire. But even iron can be remade: Isaiah 1:25 — &quot;I will turn my hand against you; I will thoroughly purge away your dross and remove all your impurities.&quot; Christ does not refuse the rebellious bronze-and-iron people but transforms them — Peter, the impetuous rock; Paul, the persecuting iron — through encounter with the crucified and risen Lord.</p>",
"29": "<p>&quot;The bellows blow fiercely; the lead is consumed in the flames; the smelter smelts in vain — the wicked are not removed.&quot; The failed refining — ordinary fire cannot purify this silver. The eschatological fire that can finally purify is the fire of judgment that Christ himself bears: his cross is the ultimate furnace in which sin&apos;s dross is finally consumed. Those who are in him pass through the fire purified (1 Cor 3:15 — &quot;the builder will suffer loss but yet will be saved — even though only as one escaping through the flames&quot;).</p>",
"30": "<p><strong>&quot;They will be called rejected silver, for the LORD has rejected them.&quot;</strong> The final verdict of the assayer: <em>kesef niʾmās</em> — rejected silver. Those who reject Christ become rejected themselves: Mark 12:10 (quoting Ps 118:22) — &quot;the stone the builders rejected has become the cornerstone.&quot; The one who was himself rejected (Isa 53:3 — &quot;despised and rejected by mankind&quot;) is the one who receives those who come to him; and those who in turn reject him become the rejected silver. The test of Jer 6:27-30 finds its final form in the stone of stumbling and the cornerstone of salvation (1 Pet 2:6-8).</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'jeremiah')
    merge_comm(existing, JEREMIAH)
    save_comm('mkt-christ', 'jeremiah', existing)
    print('Jeremiah 4-6 mkt-christ written.')

if __name__ == '__main__':
    main()
